  'vision.readyScreen': { 'zh-CN': '屏幕校准', 'zh-TW': '螢幕校準', en: 'Screen calibration' },
  'vision.readyFace': { 'zh-CN': '人脸与距离稳定', 'zh-TW': '人臉與距離穩定', en: 'Face and distance stable' },
  'vision.start': { 'zh-CN': '开始视力筛查：{eye}', 'zh-TW': '開始視力篩查：{eye}', en: 'Start Visual Acuity Screening: {eye}' },
  'vision.completeCalibrations': { 'zh-CN': '请先完成上方两项校准。', 'zh-TW': '請先完成上方兩項校準。', en: 'Complete both calibrations above first.' },
  'vision.startCameraDistance': { 'zh-CN': '请启动摄像头，将距离保持在 40–80 厘米，并确保环境光合适。', 'zh-TW': '請啟動攝影機，將距離保持在 40–80 公分，並確保環境光合適。', en: 'Start the camera, stay within 40–80 cm, and ensure suitable lighting.' },
  'vision.sample': { 'zh-CN': '视标示例', 'zh-TW': '視標範例', en: 'Sample Optotype' },
  'vision.sampleSize': { 'zh-CN': '当前屏幕换算：20/80 视标高度约为 {size} 毫米', 'zh-TW': '目前螢幕換算：20/80 視標高度約為 {size} 公釐', en: 'Current screen conversion: 20/80 height is approximately {size} mm' },
