  'vision.distanceLocked': { 'zh-CN': '距离已锁定在 {distance} 厘米', 'zh-TW': '距離已鎖定在 {distance} 公分', en: 'Distance locked at {distance} cm' },
  'vision.moveDistance': { 'zh-CN': '请移动至 40–80 厘米、调整光线并正对屏幕', 'zh-TW': '請移動至 40–80 公分、調整光線並正對螢幕', en: 'Move to 40–80 cm, adjust lighting, and face the screen' },
