  'consent.eyebrow': { 'zh-CN': '知情同意与隐私', 'zh-TW': '知情同意與隱私', en: 'CONSENT & PRIVACY' },
  'consent.title': { 'zh-CN': '由您决定摄像头和派生结果的使用方式', 'zh-TW': '由您決定攝影機和衍生結果的使用方式', en: 'You control camera use and derived-result storage' },
  'consent.intro': { 'zh-CN': '开始前请了解：摄像头仅用于估算距离、检查位置与环境光、追踪眨眼。您可随时暂停、停止或退出。', 'zh-TW': '開始前請瞭解：攝影機僅用於估算距離、檢查位置與環境光、追蹤眨眼。您可隨時暫停、停止或退出。', en: 'Before starting: the camera is used only to estimate distance, check position and lighting, and track blinks. You may pause, stop, or exit at any time.' },
  'consent.cameraTitle': { 'zh-CN': '允许 VisionGuard AI 使用摄像头', 'zh-TW': '允許 VisionGuard AI 使用攝影機', en: 'Allow VisionGuard AI to use the camera' },
  'consent.cameraDescription': { 'zh-CN': '视频帧只在当前设备本地分析；原始图片和视频绝不会被保存、上传或共享。', 'zh-TW': '視訊影格只在目前裝置本機分析；原始圖片和影片絕不會被儲存、上傳或分享。', en: 'Frames are analysed only on this device. Raw images and video are never saved, uploaded, or shared.' },
  'consent.required': { 'zh-CN': '摄像头模式必选', 'zh-TW': '攝影機模式必選', en: 'Required for camera mode' },
  'consent.storageTitle': { 'zh-CN': '在此设备保存派生筛查结果', 'zh-TW': '在此裝置儲存衍生篩查結果', en: 'Save derived screening results on this device' },
  'consent.storageDescription': { 'zh-CN': '用于筛查历史、趋势、复测提醒和持续监测报告；仅保存结构化摘要（视力、距离、眨眼/疲劳指标、校准标志和时间）。每题答案、症状答案、照片和视频均不保存。取消勾选会立即停止保存并删除已存摘要。', 'zh-TW': '用於篩查歷史、趨勢、複測提醒和持續監測報告；僅儲存結構化摘要（視力、距離、眨眼/疲勞指標、校準標記和時間）。每題答案、症狀答案、照片和影片均不儲存。取消勾選會立即停止儲存並刪除已存摘要。', en: 'Enables screening history, trends, reminders, and continuous-monitoring reports. Only structured summaries (acuity, distance, blink/fatigue measures, calibration flags, and time) are stored. Per-question answers, symptom answers, photos, and video are not retained. Unchecking immediately stops persistence and deletes saved summaries.' },
  'consent.optional': { 'zh-CN': '可选', 'zh-TW': '可選', en: 'Optional' },
  'consent.privacyTitle': { 'zh-CN': '本地处理，最少留存', 'zh-TW': '本機處理，最少留存', en: 'Local processing, minimal retention' },
  'consent.privacyBody': { 'zh-CN': '停止后摄像头轨道会关闭。只有您明确选择保存或分享时，派生摘要才会留在本机或交给您选择的应用。', 'zh-TW': '停止後攝影機軌道會關閉。只有您明確選擇儲存或分享時，衍生摘要才會留在本機或交給您選擇的應用程式。', en: 'Camera tracks close when stopped. A derived summary remains locally or goes to another app only when you explicitly save or share it.' },
  'consent.continue': { 'zh-CN': '确认并继续', 'zh-TW': '確認並繼續', en: 'Confirm and continue' },
  'consent.hint': { 'zh-CN': '请先确认摄像头用途；您仍可使用无摄像头演示。', 'zh-TW': '請先確認攝影機用途；您仍可使用無攝影機示範。', en: 'Confirm the camera purpose first. The camera-free demo remains available.' },
  'consent.saved': { 'zh-CN': '隐私选择已保存。您可以在下方随时修改。', 'zh-TW': '隱私選擇已儲存。您可以在下方隨時修改。', en: 'Privacy choices saved. You can change them here at any time.' },
  'consent.storageRevoked': { 'zh-CN': '本地结果保存已关闭，已存摘要和复测提醒已删除。', 'zh-TW': '本機結果儲存已關閉，已存摘要和複測提醒已刪除。', en: 'Local result storage is off; saved summaries and the retest reminder were deleted.' },
  'privacy.delete': { 'zh-CN': '删除本机全部筛查数据', 'zh-TW': '刪除本機全部篩查資料', en: 'Delete all local screening data' },
  'privacy.deleteConfirm': { 'zh-CN': '确定删除本机保存的筛查结果、持续监测摘要、提醒和校准数据吗？此操作无法撤销。', 'zh-TW': '確定刪除本機儲存的篩查結果、持續監測摘要、提醒和校準資料嗎？此操作無法復原。', en: 'Delete locally saved screening results, continuous-monitoring summaries, reminders, and calibration data? This cannot be undone.' },
  'privacy.deleted': { 'zh-CN': '本机筛查数据已删除；语言选择已保留。', 'zh-TW': '本機篩查資料已刪除；語言選擇已保留。', en: 'Local screening data deleted. Your language choice was kept.' },

  'symptoms.eyebrow': { 'zh-CN': '症状自述', 'zh-TW': '症狀自述', en: 'SYMPTOM CHECK' },
  'symptoms.title': { 'zh-CN': '开始测试前，告诉我们您目前的感受', 'zh-TW': '開始測試前，告訴我們您目前的感受', en: 'Tell us how your eyes feel before testing' },
  'symptoms.intro': { 'zh-CN': '症状会与视力、眨眼和距离信号一起用于分级，但不会用于诊断。', 'zh-TW': '症狀會與視力、眨眼和距離訊號一起用於分級，但不會用於診斷。', en: 'Symptoms are combined with acuity, blink, and distance signals for guidance, never diagnosis.' },
  'symptoms.legend': { 'zh-CN': '选择所有符合的项目', 'zh-TW': '選擇所有符合的項目', en: 'Select every item that applies' },
  'symptoms.redFlag': { 'zh-CN': '需及时关注', 'zh-TW': '需及時關注', en: 'Prompt attention' },
  'symptoms.redFlagTitle': { 'zh-CN': '这些症状不应等待线上筛查结果', 'zh-TW': '這些症狀不應等待線上篩查結果', en: 'Do not wait for an online screening result' },
  'symptoms.redFlagBody': { 'zh-CN': '若眼痛、复视、闪光感或飞蚊突然出现或加重，请尽快联系眼科专业人员；若症状严重，请寻求紧急医疗帮助。', 'zh-TW': '若眼痛、複視、閃光感或飛蚊突然出現或加重，請儘快聯絡眼科專業人員；若症狀嚴重，請尋求緊急醫療協助。', en: 'If eye pain, double vision, flashes, or floaters are sudden or worsening, contact an eye-care professional promptly; seek urgent care for severe symptoms.' },
  'symptoms.complete': { 'zh-CN': '完成症状填写', 'zh-TW': '完成症狀填寫', en: 'Complete symptom check' },
  'symptoms.required': { 'zh-CN': '请选择一项；若没有症状，请选择“目前无明显症状”。', 'zh-TW': '請選擇一項；若沒有症狀，請選擇「目前無明顯症狀」。', en: 'Select an item, or choose “No noticeable symptoms” if none apply.' },
  'symptoms.completedTitle': { 'zh-CN': '症状信息已记录（仅本次会话）', 'zh-TW': '症狀資訊已記錄（僅本次工作階段）', en: 'Symptom information recorded for this session' },
  'symptoms.completedBody': { 'zh-CN': '这些选择不会包含在原始影像中，也不会自动发送给任何机构。', 'zh-TW': '這些選擇不會包含在原始影像中，也不會自動傳送給任何機構。', en: 'These choices are not part of camera media and are never automatically sent to an organisation.' },
