  'symptoms.edit': { 'zh-CN': '修改', 'zh-TW': '修改', en: 'Edit' },
  'symptoms.choice.blurredVision': { 'zh-CN': '视物模糊', 'zh-TW': '視物模糊', en: 'Blurred vision' },
  'symptoms.choice.blurredVisionDesc': { 'zh-CN': '近处或远处难以看清', 'zh-TW': '近處或遠處難以看清', en: 'Difficulty seeing clearly near or far' },
  'symptoms.choice.eyeStrainDryness': { 'zh-CN': '眼疲劳、干涩或灼热', 'zh-TW': '眼疲勞、乾澀或灼熱', en: 'Eye strain, dryness, or burning' },
