  'explanation.riskDesc.normal': { 'zh-CN': '当前没有明确的筛查风险信号。继续保持良好距离、完整眨眼和定期休息。', 'zh-TW': '目前沒有明確的篩查風險訊號。繼續保持良好距離、完整眨眼和定期休息。', en: 'No clear screening risk signal is present. Keep a healthy distance, blink fully, and take regular breaks.' },
  'explanation.riskDesc.caution': { 'zh-CN': '发现一项需要调整的信号。先休息和调整环境，再观察是否持续。', 'zh-TW': '發現一項需要調整的訊號。先休息和調整環境，再觀察是否持續。', en: 'One signal needs adjustment. Rest, improve the setup, and see whether it persists.' },
  'explanation.riskDesc.concern': { 'zh-CN': '发现较强或多项并存的风险信号。请按下一步建议处理，不要把筛查当作诊断。', 'zh-TW': '發現較強或多項並存的風險訊號。請按下一步建議處理，不要把篩查當作診斷。', en: 'A stronger or combined set of signals was found. Follow the next-step guidance and do not treat screening as a diagnosis.' },
  'explanation.notDiagnosis': { 'zh-CN': '本工具仅用于筛查，不能诊断近视、散光或眼病。', 'zh-TW': '本工具僅用於篩查，不能診斷近視、散光或眼病。', en: 'This tool screens only; it cannot diagnose myopia, astigmatism, or eye disease.' },
  'explanation.professionalCue': { 'zh-CN': '若结果异常、症状持续或您担心视力，请联系验光师、眼科专业人员或校园健康中心。', 'zh-TW': '若結果異常、症狀持續或您擔心視力，請聯絡驗光師、眼科專業人員或校園健康中心。', en: 'If a result is abnormal, symptoms persist, or you are worried about your vision, contact an optometrist, eye-care professional, or campus health service.' },
